```

### Associated Type

```aria
// Type decided by implementation
trait Iterator {
    type Item;  // Associated type

    fn next() -> Option<Self::Item>;
}

// Type determined by trait impl
struct NumberIterator;

impl Iterator for NumberIterator {
    type Item = i32;  // Concrete type

    fn next() -> Option<i32> { }
```

