## Common Generic Struct Patterns

### Option Type

```aria
enum Option<T> {
    Some(T),
    None
}

impl<T> Option<T> {
    fn is_some() -> bool {
        return match self {
            Some(_) => true,
            None => false
        };
    }

    fn unwrap() -> T {
        return match self {
            Some(value) => value,
            None => panic("Called unwrap on None")
        };
    }

    fn unwrap_or(default: T) -> T {
        return match self {
            Some(value) => value,
            None => default
        };
    }
```

### Result Type

```aria
enum Result<T, E> {
    Ok(T),
    Err(E)
}

impl<T, E> Result<T, E> {
    fn is_ok() -> bool {
        return match self {
            Ok(_) => true,
            Err(_) => false
        };
    }

    fn unwrap() -> T {
        return match self {
            Ok(value) => value,
            Err(_) => panic("Called unwrap on Err")
        };
    }
```

