        flt64:zero = 0.0;
        flt64:half_dt = dt * 0.5;
        flt64:ax = zero - px1;
        pv1 = pv1 + half_dt * ax;
        px1 = px1 + dt * pv1;
        flt64:ax2 = zero - px1;
        pv1 = pv1 + half_dt * ax2;
    }

    flt64:px2 = 1.0;
    flt64:pv2 = 0.0;
    till(100, 1) {
        flt64:zero2 = 0.0;
        flt64:half_dt2 = dt * 0.5;
        flt64:ax_b = zero2 - px2;
        pv2 = pv2 + half_dt2 * ax_b;
        px2 = px2 + dt * pv2;
        flt64:ax2_b = zero2 - px2;
        pv2 = pv2 + half_dt2 * ax2_b;
    }

    if (px1 != px2) {
        print("FAIL: 100-step physics simulation non-deterministic (position)\n");
        failures = failures + 1;
    }
    if (pv1 != pv2) {
        print("FAIL: 100-step physics simulation non-deterministic (velocity)\n");
        failures = failures + 1;
    }

    // ========================================================================
    // RESULT
    // ========================================================================
    if (failures == 0) {
        print("DETERMINISM VERIFICATION: ALL TESTS PASSED\n");
        pass(0);
    }
    pass(1);
};

