// aria-display: Cross-platform terminal display library for the Aria virtual console.
//
// Provides ANSI/termios-backed TUI primitives:
//   - Raw mode control (enter/exit/query)
//   - Cursor positioning and visibility
//   - Screen and line clearing
//   - 16-color foreground/background attributes + bold/reverse
//   - Drawing primitives: hline, vline, box
//   - Text-at-position (pure Aria: move + color + print)
//   - Terminal size query
//   - Frame flush
//
// Color constants (pass as int32 to set_fg / set_bg):
//   0=black  1=red  2=green  3=yellow  4=blue  5=magenta  6=cyan  7=white
//   8-15=bright variants   (0-1)=reset to default
//
// Backend: POSIX termios + ANSI escape codes via shim/aria_display_shim.c
// Future backends (X11, Win32, Cocoa) expose the same function names.
//
// Link with: -L<shim_dir> -laria_display -Wl,-rpath,'$ORIGIN/../shim'

extern "aria_display" {
    func:aria_display_enter_raw    = int32();
    func:aria_display_exit_raw     = int32();
    func:aria_display_is_raw       = int32();
    func:aria_display_move         = int32(int32:col, int32:row);
    func:aria_display_home         = int32();
    func:aria_display_hide_cursor  = int32();
    func:aria_display_show_cursor  = int32();
    func:aria_display_clear        = int32();
    func:aria_display_clear_eol    = int32();
    func:aria_display_clear_eos    = int32();
    func:aria_display_set_fg       = int32(int32:color);
    func:aria_display_set_bg       = int32(int32:color);
    func:aria_display_reset_attr   = int32();
    func:aria_display_set_bold     = int32(int32:on);
    func:aria_display_set_reverse  = int32(int32:on);
    func:aria_display_hline        = int32(int32:col, int32:row, int32:fg, int32:bg, int32:ch, int32:w);
    func:aria_display_vline        = int32(int32:col, int32:row, int32:fg, int32:bg, int32:ch, int32:h);
    func:aria_display_box          = int32(int32:col, int32:row, int32:fg, int32:bg, int32:w, int32:h);
    func:aria_display_get_size     = int64();
    func:aria_display_flush        = int32();
}

