};

// Extract column count from a packed size value returned by disp_size().
pub func:disp_cols = int32(int64:packed) {
    uint64:upacked = @cast<uint64>(packed);
    uint64:shifted = upacked >> 32u64;
    int32:cols = @cast<int32>(shifted);
    pass(cols);
};

// Extract row count from a packed size value returned by disp_size().
pub func:disp_rows = int32(int64:packed) {
    uint64:upacked = @cast<uint64>(packed);
    uint64:mask = 4294967295u64;
    uint64:low = upacked & mask;
    int32:rows = @cast<int32>(low);
    pass(rows);
};

